// TestUpgradeVectors_ConcurrentAccess tests thread safety during vector upgrades
func TestUpgradeVectors_ConcurrentAccess(t *testing.T) {
	domains := []*DomainExamples{
		{
			Domain: "test",
			Examples: []Example{
				{Query: "test query one", Intent: "intent1"},
				{Query: "test query two", Intent: "intent2"},
				{Query: "test query three", Intent: "intent3"},
			},
		},
	}

	c := NewEmbeddingClassifier(domains, 0.5)

	// Create slow embedder to ensure concurrent access happens during upgrade
	mock := newMockEmbedder()
	mock.embedBatchFunc = func(texts []string) ([][]float32, error) {
		time.Sleep(50 * time.Millisecond) // Simulate slow embedding service
		results := make([][]float32, len(texts))
		for i := range texts {
			results[i] = []float32{0.1, 0.2, 0.3}
		}
		return results, nil
	}

	// Start concurrent operations
	var wg sync.WaitGroup
	errChan := make(chan error, 1)

	// Goroutine 1: Upgrade vectors
	wg.Add(1)
	go func() {
		defer wg.Done()
		err := c.UpgradeVectors(mock)
		if err != nil {
			errChan <- err
		}
	}()

	// Goroutine 2-4: Query while upgrading
	for i := 0; i < 3; i++ {
		wg.Add(1)
		go func() {
			defer wg.Done()
			ctx := context.Background()
			for j := 0; j < 10; j++ {
				// Should not panic during concurrent access
				_, _ = c.FindBestMatch(ctx, "test query")
				time.Sleep(5 * time.Millisecond)
			}
		}()
	}

	wg.Wait()
	close(errChan)

	// Verify no errors occurred
	for err := range errChan {
		require.NoError(t, err)
	}

	// Verify classifier still works after concurrent operations
	ctx := context.Background()
	match, score := c.FindBestMatch(ctx, "test query one")
	assert.NotNil(t, match)
	assert.Greater(t, score, 0.0)
}

// TestCosineSimilarity tests cosine similarity calculation
func TestCosineSimilarity(t *testing.T) {
	// These tests verify the cosine similarity math used internally
	// by creating classifiers and observing match scores

	tests := []struct {
		name          string
		query1        string
		query2        string
		expectSimilar bool
	}{
		{
			name:          "identical queries",
			query1:        "Show delayed deliveries",
			query2:        "Show delayed deliveries",
			expectSimilar: true, // Should have score near 1.0
		},
		{
			name:          "very different queries",
			query1:        "Show delayed deliveries",
			query2:        "weather forecast tomorrow",
			expectSimilar: false, // Should have low score
		},
		{
			name:          "lexical overlap",
			query1:        "Show delivery status",
			query2:        "Check delivery progress",
			expectSimilar: true, // Share "delivery" token (BM25 is lexical, not semantic)
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			// Create classifier with first query as example
			domains := []*DomainExamples{
				{
					Domain: "test",
					Examples: []Example{
						{Query: tt.query1, Intent: "test_intent"},
					},
				},
			}

			c := NewEmbeddingClassifier(domains, 0.3)
			ctx := context.Background()

			// Find match for second query
			match, score := c.FindBestMatch(ctx, tt.query2)

			if tt.expectSimilar {
				assert.NotNil(t, match)
				// BM25 with feature hashing: single token overlap yields ~0.3-0.5 similarity
				assert.Greater(t, score, 0.3, "Similar queries should have measurable similarity")
			} else {
				// Either no match or low score
				if match != nil {
					assert.Less(t, score, 0.3, "Different queries should have low similarity")
				}
			}
		})
	}
}

